using System.Text.Json;

namespace Payments;

/// <summary>Abstracts the underlying payment provider (Stripe, Adyen, …).</summary>
public interface IPaymentProvider
{
    Task<ChargeResult> ChargeAsync(string cardToken, decimal amount);
    Task<RefundResult> RefundAsync(string chargeId);
}

/// <summary>Receives webhook event notifications.</summary>
public interface IWebhookHandler
{
    Task HandleAsync(WebhookEvent webhookEvent);
}

// ── Result / event types ────────────────────────────────────────────

public record ChargeResult(string ChargeId, bool Success, string? ErrorMessage = null);
public record RefundResult(string RefundId, bool Success, string? ErrorMessage = null);

public record WebhookEvent(string EventType, string ResourceId, JsonElement? Payload);

// ── Gateway ─────────────────────────────────────────────────────────

public sealed class PaymentGateway
{
    private readonly IPaymentProvider _provider;
    private readonly IWebhookHandler? _webhookHandler;

    public const decimal MinChargeAmount = 0.50m;
    public const decimal MaxChargeAmount = 999_999.99m;

    public PaymentGateway(IPaymentProvider provider, IWebhookHandler? webhookHandler = null)
    {
        _provider = provider ?? throw new ArgumentNullException(nameof(provider));
        _webhookHandler = webhookHandler;
    }

    /// <summary>Validates inputs and delegates to the provider.</summary>
    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token must not be empty.", nameof(cardToken));

        if (amount < MinChargeAmount)
            throw new ArgumentOutOfRangeException(nameof(amount),
                $"Amount must be at least {MinChargeAmount}.");

        if (amount > MaxChargeAmount)
            throw new ArgumentOutOfRangeException(nameof(amount),
                $"Amount must not exceed {MaxChargeAmount}.");

        return await _provider.ChargeAsync(cardToken, amount);
    }

    /// <summary>Validates the charge ID and delegates the refund.</summary>
    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID must not be empty.", nameof(chargeId));

        return await _provider.RefundAsync(chargeId);
    }

    /// <summary>Parses raw JSON into a <see cref="WebhookEvent"/> and dispatches it.</summary>
    public async Task ProcessWebhookAsync(string rawJson)
    {
        if (string.IsNullOrWhiteSpace(rawJson))
            throw new ArgumentException("Webhook payload must not be empty.", nameof(rawJson));

        WebhookEvent webhookEvent;
        try
        {
            using var doc = JsonDocument.Parse(rawJson);
            var root = doc.RootElement;

            var eventType = root.GetProperty("event_type").GetString()
                ?? throw new InvalidOperationException("Missing event_type.");
            var resourceId = root.GetProperty("resource_id").GetString()
                ?? throw new InvalidOperationException("Missing resource_id.");

            // Clone the payload so it survives the JsonDocument disposal.
            JsonElement? payload = root.TryGetProperty("payload", out var p)
                ? p.Clone()
                : null;

            webhookEvent = new WebhookEvent(eventType, resourceId, payload);
        }
        catch (JsonException ex)
        {
            throw new FormatException("Invalid webhook JSON.", ex);
        }

        if (_webhookHandler is null)
            throw new InvalidOperationException("No webhook handler registered.");

        await _webhookHandler.HandleAsync(webhookEvent);
    }
}

