using System.Text.Json;
using Moq;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayChargeTests
{
    private Mock<IPaymentProvider> _provider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _provider = new Mock<IPaymentProvider>();
        _gateway = new PaymentGateway(_provider.Object);
    }

    // ── Happy-path ──────────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccessResult()
    {
        var expected = new ChargeResult("ch_123", true);
        _provider.Setup(p => p.ChargeAsync("tok_visa", 49.99m))
                 .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderFails_ReturnsFailureResult()
    {
        var expected = new ChargeResult("", false, "Card declined");
        _provider.Setup(p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
                 .ReturnsAsync(expected);

        var result = await _gateway.ChargeAsync("tok_visa", 10m);

        Assert.IsFalse(result.Success);
        Assert.AreEqual("Card declined", result.ErrorMessage);
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_Succeeds()
    {
        _provider.Setup(p => p.ChargeAsync(It.IsAny<string>(), PaymentGateway.MinChargeAmount))
                 .ReturnsAsync(new ChargeResult("ch_min", true));

        var result = await _gateway.ChargeAsync("tok_visa", PaymentGateway.MinChargeAmount);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MaximumAmount_Succeeds()
    {
        _provider.Setup(p => p.ChargeAsync(It.IsAny<string>(), PaymentGateway.MaxChargeAmount))
                 .ReturnsAsync(new ChargeResult("ch_max", true));

        var result = await _gateway.ChargeAsync("tok_visa", PaymentGateway.MaxChargeAmount);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_DelegatesToProviderWithCorrectArgs()
    {
        _provider.Setup(p => p.ChargeAsync("tok_amex", 75.00m))
                 .ReturnsAsync(new ChargeResult("ch_456", true));

        await _gateway.ChargeAsync("tok_amex", 75.00m);

        _provider.Verify(p => p.ChargeAsync("tok_amex", 75.00m), Times.Once);
    }

    // ── Validation failures ─────────────────────────────────────────

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountBelowMinimum_ThrowsArgumentOutOfRange()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_visa", 0.10m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRange()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRange()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_visa", -5m));
    }

    [TestMethod]
    public async Task ChargeAsync_AmountExceedsMaximum_ThrowsArgumentOutOfRange()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_visa", 1_000_000m));
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _provider.Setup(p => p.ChargeAsync(It.IsAny<string>(), It.IsAny<decimal>()))
                 .ThrowsAsync(new InvalidOperationException("Network error"));

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_visa", 10m));
    }
}

