[TestClass]
public class PaymentGatewayWebhookTests
{
    private Mock<IPaymentProvider> _provider = null!;
    private Mock<IWebhookHandler> _webhookHandler = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _provider = new Mock<IPaymentProvider>();
        _webhookHandler = new Mock<IWebhookHandler>();
        _gateway = new PaymentGateway(_provider.Object, _webhookHandler.Object);
    }

    // ── Happy-path ──────────────────────────────────────────────────

    [TestMethod]
    public async Task ProcessWebhookAsync_ValidJson_DispatchesToHandler()
    {
        var json = """{"event_type":"charge.succeeded","resource_id":"ch_123"}""";

        await _gateway.ProcessWebhookAsync(json);

        _webhookHandler.Verify(h => h.HandleAsync(
            It.Is<WebhookEvent>(e =>
                e.EventType == "charge.succeeded" &&
                e.ResourceId == "ch_123")),
            Times.Once);
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_WithPayload_PassesPayloadToHandler()
    {
        var json = """
        {
            "event_type": "refund.created",
            "resource_id": "re_456",
            "payload": { "amount": 25.00, "currency": "USD" }
        }
        """;

        WebhookEvent? captured = null;
        _webhookHandler.Setup(h => h.HandleAsync(It.IsAny<WebhookEvent>()))
                       .Callback<WebhookEvent>(e => captured = e)
                       .Returns(Task.CompletedTask);

        await _gateway.ProcessWebhookAsync(json);

        Assert.IsNotNull(captured);
        Assert.AreEqual("refund.created", captured.EventType);
        Assert.AreEqual("re_456", captured.ResourceId);
        Assert.IsNotNull(captured.Payload);
        Assert.AreEqual(25.00m, captured.Payload.Value.GetProperty("amount").GetDecimal());
        Assert.AreEqual("USD", captured.Payload.Value.GetProperty("currency").GetString());
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_WithoutPayload_PayloadIsNull()
    {
        var json = """{"event_type":"ping","resource_id":"sys_001"}""";

        WebhookEvent? captured = null;
        _webhookHandler.Setup(h => h.HandleAsync(It.IsAny<WebhookEvent>()))
                       .Callback<WebhookEvent>(e => captured = e)
                       .Returns(Task.CompletedTask);

        await _gateway.ProcessWebhookAsync(json);

        Assert.IsNotNull(captured);
        Assert.IsNull(captured.Payload);
    }

    // ── Validation failures ─────────────────────────────────────────

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ProcessWebhookAsync_EmptyPayload_ThrowsArgumentException(string? rawJson)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ProcessWebhookAsync(rawJson!));
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_MalformedJson_ThrowsFormatException()
    {
        await Assert.ThrowsExceptionAsync<FormatException>(
            () => _gateway.ProcessWebhookAsync("{not-json!!}"));
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_MissingEventType_Throws()
    {
        var json = """{"resource_id":"ch_123"}""";

        // Missing required property → KeyNotFoundException wrapped in FormatException or direct throw
        await Assert.ThrowsExceptionAsync<FormatException>(
            () => _gateway.ProcessWebhookAsync(json));
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_MissingResourceId_Throws()
    {
        var json = """{"event_type":"charge.succeeded"}""";

        await Assert.ThrowsExceptionAsync<FormatException>(
            () => _gateway.ProcessWebhookAsync(json));
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_NoHandlerRegistered_ThrowsInvalidOperation()
    {
        var gatewayWithoutHandler = new PaymentGateway(_provider.Object);
        var json = """{"event_type":"charge.succeeded","resource_id":"ch_123"}""";

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => gatewayWithoutHandler.ProcessWebhookAsync(json));
    }

    [TestMethod]
    public async Task ProcessWebhookAsync_HandlerThrows_ExceptionPropagates()
    {
        _webhookHandler.Setup(h => h.HandleAsync(It.IsAny<WebhookEvent>()))
                       .ThrowsAsync(new ApplicationException("Handler failed"));

        var json = """{"event_type":"charge.succeeded","resource_id":"ch_123"}""";

        await Assert.ThrowsExceptionAsync<ApplicationException>(
            () => _gateway.ProcessWebhookAsync(json));
    }
}

